INSERT INTO 
    bird_details (bird_id, scientific_name, power_text, note)
VALUES
    (1, 'Melanerpes formicivorus', 'Gain 1 [seed] from the birdfeeder, if available. You may cache it on this bird.', 'The birds with these powers are known for caching extra food and saving it for later. As noted on these cards, you can cache exactly 1 food token when their power is activated by placing it on a bird card. Once a food token is cached on a bird card, you cannot spend it. Each token on the card at the end of the game is worth 1 point. If the same dice are showing in the birdfeeder, you may reroll to see if you meet the condition of the bird. If you run out of food tokens, you can cache cards instead.'),
    (2, 'Recurvirostra americana', 'When another player takes the “lay eggs” action, lay 1 [egg] on another bird with a [ground] nest.', 'These birds are all nest parasites in the wild: they lay eggs in other birds'' nests. Cowbirds don''t even build their own nests.<br>When another player uses the [grassland] action to lay eggs, you may lay 1 egg. You may do this only once between your turns, no matter how many other players lay eggs. The cowbird can lay eggs on star nests.'),
    (3, 'Botaurus lentiginosus', 'Player(s) with the fewest birds in their [wetland] draw 1 [card].', 'If players are tied for the fewest birds currently in the wetland habitat, all draw a card, starting with you and proceeding clockwise. All may draw from the deck or the face-up cards.'),
    (4, 'Fulica americana', 'Tuck 1 [card] from your hand behind this bird. If you do, draw 1 [card].', 'These birds all allow you to tuck a card from your hand for a point, then gain some additional benefit (lay an egg, draw a card, or gain a food). You can only gain the benefit if you first tuck a card from your hand.'),
    (5, 'Corvus brachyrhynchos', 'Discard 1 [egg] from any of your other birds to gain 1 [wild] from the supply.', 'These birds are all known for eating eggs from other birds'' nests. You must have laid an egg on another bird before you can use these powers. Discard the egg to the supply.'),
    (6, 'Spinus tristis', 'Gain 3 [seed] from the supply.', NULL),
    (7, 'Falco sparverius', 'Roll all dice not in birdfeeder. If any are [rodent], cache 1 [rodent] from the supply on this bird.', 'Birds that eat rodents or fish roll all dice that are not in the birdfeeder. (Note that you will never roll more than 4 dice, because when all 5 dice are out of the birdfeeder it must reset immediately.) Roll dice on the table; they do not go back into the birdfeeder. If one or more dice show the specified type, take at most 1 token of that type from the supply and cache it on your card (see “Caching food”). Each token on a bird card is worth 1 point at the end of the game.'),
    (8, 'Haematopus palliatus', 'Draw [card] equal to the number of players +1. Starting with you and proceeding clockwise, each player selects 1 of those cards and places it in their hand. You keep the extra card.', 'Draw the cards from the deck so that you have a set with one more card than there are players. Each player chooses one card from this set, starting with you and passing to the left. When everyone has chosen a card, you keep the extra card.'),
    (9, 'Setophaga ruticilla', 'Gain 1 [die] from the birdfeeder.', NULL),
    (10, 'Turdus migratorius', 'Tuck 1 [card] from your hand behind this bird. If you do, draw 1 [card].', 'These birds all allow you to tuck a card from your hand for a point, then gain some additional benefit (lay an egg, draw a card, or gain a food). You can only gain the benefit if you first tuck a card from your hand.'),
    (11, 'Pelecanus erythrorhynchos', 'Discard 1 [fish] to tuck 2 [card] from the deck behind this bird.', 'These powers allow you to discard a specific type of food to take 2 cards from the deck and tuck them behind the bird. You must have the food in your personal supply; you cannot take it from a bird card.'),
    (12, 'Scolopax minor', NULL, NULL),
    (13, 'Anhinga anhinga', 'Roll all dice not in birdfeeder. If any are [fish], cache 1 [fish] from the supply on this bird.', 'Birds that eat rodents or fish roll all dice that are not in the birdfeeder. (Note that you will never roll more than 4 dice, because when all 5 dice are out of the birdfeeder it must reset immediately.) Roll dice on the table; they do not go back into the birdfeeder. If one or more dice show the specified type, take at most 1 token of that type from the supply and cache it on your card (see “Caching food”). Each token on a bird card is worth 1 point at the end of the game.'),
    (14, 'Calypte anna', 'Each player gains 1 [die] from the birdfeeder, starting with the player of your choice.', 'The hummingbird''s owner decides which person gains the first food, and then players gain food in turn order. Players may reset the birdfeeder if it is empty or if all dice are showing the same face.'),
    (15, 'Myiarchus cinerascens', 'Lay 1 [egg] on each of your birds with a [cavity] nest.', 'This power allows you to lay eggs on all of your birds that have a specific nest symbol (and all birds with a star nest symbol), including the newly played bird.'),
    (16, 'Fratercula arctica', 'Draw 2 new bonus cards and keep 1.', 'Draw two goal cards, pick the one you want to keep, and discard the other. If the deck of goal cards is ever exhausted, shuffle the discards to form a new face-down deck.<br>The birds with this power are all threatened or endangered, or conservationists are concerned that they soon will be because of a declining trend in their population.'),
    (17, 'Ammodramus bairdii', 'Lay 1 [egg] on any bird.', NULL),
    (18, 'Haliaeetus leucocephalus', 'Gain all [fish] that are in the birdfeeder.', NULL),
    (19, 'Icterus galbula', 'All players gain 1 [fruit] from the supply.', NULL),
    (20, 'Tyto alba', 'Roll all dice not in birdfeeder. If any are [rodent], cache 1 [rodent] from the supply on this bird.', 'Birds that eat rodents or fish roll all dice that are not in the birdfeeder. (Note that you will never roll more than 4 dice, because when all 5 dice are out of the birdfeeder it must reset immediately.) Roll dice on the table; they do not go back into the birdfeeder. If one or more dice show the specified type, take at most 1 token of that type from the supply and cache it on your card (see “Caching food”). Each token on a bird card is worth 1 point at the end of the game.'),
    (21, 'Hirundo rustica', 'Tuck 1 [card] from your hand behind this bird. If you do, draw 1 [card].', 'These birds all allow you to tuck a card from your hand for a point, then gain some additional benefit (lay an egg, draw a card, or gain a food). You can only gain the benefit if you first tuck a card from your hand.'),
    (22, 'Strix varia', 'Look at a [card] from the deck. If less than 75cm, tuck it behind this bird. If not, discard it.', 'These birds eat other birds. Look at the wingspan of the top card of the deck and compare it to their hunting power.<br>If the wingspan of the top card in the deck is less than the bird''s hunting power, tuck that card to signify that your predator hunted successfully. Each tucked card is worth 1 point at the end of the game.<br>If the wingspan of the top card is equal to or larger than your predator''s power, discard the card instead.'),
    (23, 'Bucephala islandica', 'When another player takes the “lay eggs” action, lay 1 [egg] on another bird with a [cavity] nest.', 'These birds are all nest parasites in the wild: they lay eggs in other birds'' nests. Cowbirds don''t even build their own nests.<br>When another player uses the [grassland] action to lay eggs, you may lay 1 egg. You may do this only once between your turns, no matter how many other players lay eggs. The cowbird can lay eggs on star nests.'),
    (24, 'Vireo bellii', 'Draw 2 new bonus cards and keep 1.', 'Draw two goal cards, pick the one you want to keep, and discard the other. If the deck of goal cards is ever exhausted, shuffle the discards to form a new face-down deck.<br>The birds with this power are all threatened or endangered, or conservationists are concerned that they soon will be because of a declining trend in their population.'),
    (25, 'Megaceryle alcyon', 'When another player plays a bird in their [wetland], gain 1 [fish] from the supply.', 'Activate these powers when a player uses the “Play a bird” action to play a bird into the specific habitat. A bird that uses its power to move into the habitat does not trigger this power.'),
    (26, 'Thryomanes bewickii', 'If this bird is to the right of all other birds in its habitat, move it to another habitat.', 'These birds are all able to live in a variety of habitats, and their power is to move from habitat to habitat—but only if they''re the last bird in that row. (They can be in any column.) This can be powerful for increasing your abilities in multiple habitats, and for scoring on end-of-round goals. Be careful not to play another bird to the right of one of these cards, or you won''t be able to use its power!'),
    (27, 'Rynchops niger', 'Roll all dice not in birdfeeder. If any are [fish], cache 1 [fish] from the supply on this bird.', 'Birds that eat rodents or fish roll all dice that are not in the birdfeeder. (Note that you will never roll more than 4 dice, because when all 5 dice are out of the birdfeeder it must reset immediately.) Roll dice on the table; they do not go back into the birdfeeder. If one or more dice show the specified type, take at most 1 token of that type from the supply and cache it on your card (see “Caching food”). Each token on a bird card is worth 1 point at the end of the game.'),
    (28, 'Chlidonias niger', 'Draw 1 [card]. If you do, discard 1 [card] from your hand at the end of your turn.', 'This power adds cards to the wetland''s draw card(s) action, but it has a cost. The next player may start their turn while you are deciding which card(s) to discard.'),
    (29, 'Coragyps atratus', 'When another player''s [predator] succeeds, gain 1 [die] from the birdfeeder.', 'If multiple players trigger this power at the same time, they gain food in turn order, starting to the left of the active player (the one whose predator succeeded).'),
    (30, 'Dendrocygna autumnalis', 'Discard 1 [seed] to tuck 2 [card] from the deck behind this bird.', 'These powers allow you to discard a specific type of food to take 2 cards from the deck and tuck them behind the bird. You must have the food in your personal supply; you cannot take it from a bird card.'),
    (31, 'Pica hudsonia', 'When another player''s [predator] succeeds, gain 1 [die] from the birdfeeder.', 'If multiple players trigger this power at the same time, they gain food in turn order, starting to the left of the active player (the one whose predator succeeded).'),
    (32, 'Archilochus alexandri', 'All players gain 1 [fruit] from the supply.', NULL),
    (33, 'Nycticorax nycticorax', 'Discard 1 [egg] from any of your other birds to gain 1 [wild] from the supply.', 'These birds are all known for eating eggs from other birds'' nests. You must have laid an egg on another bird before you can use these powers. Discard the egg to the supply.'),
    (34, 'Himantopus mexicanus', 'Draw 2 [card].', 'This power adds cards to the wetland''s draw card(s) action. You may draw from the deck or the face-up cards. Face-up cards are refilled only at the end of your turn.'),
    (35, 'Passerina caerulea', 'If this bird is to the right of all other birds in its habitat, move it to another habitat.', 'These birds are all able to live in a variety of habitats, and their power is to move from habitat to habitat—but only if they''re the last bird in that row. (They can be in any column.) This can be powerful for increasing your abilities in multiple habitats, and for scoring on end-of-round goals. Be careful not to play another bird to the right of one of these cards, or you won''t be able to use its power!'),
